"""
vault/search.py — agentvault
Keyword search over vault_index.json.
Exposes FastAPI /search?q= endpoint.

Run: uvicorn vault.search:app --host 0.0.0.0 --port 8080
"""

import json
import os
from pathlib import Path
from datetime import datetime, timezone

try:
    from fastapi import FastAPI, Query
    from fastapi.middleware.cors import CORSMiddleware
except ImportError:
    raise ImportError("pip install fastapi uvicorn")

INDEX_PATH = Path(os.environ.get("VAULT_INDEX_PATH", "vault_index.json"))
EXPORT_DIR = Path(os.environ.get("VAULT_EXPORT_DIR", "exports"))

app = FastAPI(title="AgentVault Search", version="1.0.0")
app.add_middleware(CORSMiddleware, allow_origins=["*"], allow_methods=["*"], allow_headers=["*"])


def load_index() -> dict:
    if INDEX_PATH.exists():
        return json.loads(INDEX_PATH.read_text())
    return {"entries": [], "hashes": []}


def keyword_match(entry: dict, query: str) -> bool:
    q = query.lower()
    if q in entry.get("filename", "").lower():
        return True
    if any(q in t.lower() for t in entry.get("key_topics", [])):
        return True
    fpath = EXPORT_DIR / entry["filename"]
    if fpath.exists():
        return q in fpath.read_text(errors="ignore").lower()
    return False


@app.get("/search")
def search(q: str = Query(..., description="Search query"), limit: int = 20):
    idx = load_index()
    results = [e for e in idx["entries"] if keyword_match(e, q)]
    return {
        "query": q,
        "count": len(results),
        "results": results[:limit],
        "fetched_at": datetime.now(timezone.utc).isoformat(),
    }


@app.get("/index")
def index_list(limit: int = 50):
    idx = load_index()
    return {"total": len(idx["entries"]), "entries": idx["entries"][-limit:]}


@app.get("/health")
def health():
    return {"status": "ok", "ts": datetime.now(timezone.utc).isoformat()}

#!/usr/bin/env python3
"""
agentvault Heartbeat — 15-minute pulse.
Checks vault index health, emits status to evez-autonomous-ledger.
"""
import os, json, datetime, hashlib, requests, base64

GH_TOKEN = os.environ.get("GITHUB_TOKEN", "")
ABLY_KEY = os.environ.get("ABLY_KEY", "")
OWNER = "EvezArt"

HEADERS = {
    "Authorization": f"Bearer {GH_TOKEN}",
    "Accept": "application/vnd.github+json",
    "X-GitHub-Api-Version": "2022-11-28",
}


def now_iso():
    return datetime.datetime.utcnow().isoformat() + "Z"


def get_vault_contents():
    url = f"https://api.github.com/repos/{OWNER}/agentvault/contents/exports"
    r = requests.get(url, headers=HEADERS)
    if r.status_code == 200:
        return len(r.json())
    return 0


def post_heartbeat(count):
    event = {
        "type": "vault_heartbeat",
        "source": "agentvault",
        "timestamp": now_iso(),
        "export_count": count,
        "hash": hashlib.sha256(f"vault_{count}_{now_iso()}".encode()).hexdigest()[:16],
    }
    content = json.dumps(event, indent=2)
    encoded = base64.b64encode(content.encode()).decode()
    ts = now_iso().replace(":", "-").replace(".", "-")
    url = f"https://api.github.com/repos/{OWNER}/evez-autonomous-ledger/contents/DECISIONS/{ts}_vault_heartbeat.json"
    requests.put(url, headers=HEADERS, json={
        "message": f"🦠 vault heartbeat @ {event['timestamp']}",
        "content": encoded,
    })
    if ABLY_KEY:
        key_id, key_secret = ABLY_KEY.split(":")
        requests.post(
            "https://rest.ably.io/channels/evez-ops/messages",
            json={"name": "vault_heartbeat", "data": json.dumps(event)},
            auth=(key_id, key_secret)
        )


def main():
    print(f"\n🦠 agentvault Heartbeat — {now_iso()}")
    count = get_vault_contents()
    print(f"  Export count: {count}")
    post_heartbeat(count)
    print("  ✅ Vault pulse written to ledger.")


if __name__ == "__main__":
    main()

